INSERT INTO "Review" ("id", "userId", "name", "educationalInstitution", "rating", "text", "isPublished", "createdAt") VALUES
('cmp67i07905mplk9cx5irqm9t', 'cmp66xjdd00kulktgv8na0emi', 'Слепцов Евгений Германович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-22, 4 курс', '4', 'Хороший рабочий курс: и лекции, и задания, и итоговый документ. Отняла балл только то, что к концу устала от однотипных формулировок в подсказках, но по содержанию всё честно и по делу.', 't', '2026-04-08 22:44:46.931'),
('cmp67i07a05mrlk9cdqmbnsnl', 'cmp66xjdg00kxlktg1n3oapve', 'Степанов Руслан Сергеевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-22, 4 курс', '4', 'Удобно совмещать с работой: чёткие дедлайны по модулям не дают забросить. Сертификат получил. Минус — иногда долгая загрузка страниц, на контент не влияет.', 't', '2026-04-14 06:56:15.31'),
('cmp67i07a05mtlk9cf3utii8y', 'cmp66xjdi00l0lktgo162z06b', 'Тимирдяев Тускун Николаевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-22, 4 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-04-08 13:27:56.852'),
('cmp67i07b05mvlk9cppxqfaxu', 'cmp66xjdj00l3lktgx4w5t62f', 'Цвикальский Артем Андреевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-22, 4 курс', '3', 'Ровный курс, прошёл до конца. Тесты справедливые, практика полезная. Четвёрку не ставлю из‑за ощущения «чуть не дожали» финал.', 't', '2026-04-11 19:31:25.568'),
('cmp67i07b05mzlk9ck4eop0wv', 'cmp677s8d00l9lk1vkj672t1y', 'Заровняев Влад Николаевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-24, 2 курс', '3', 'Нормально для обязательного блока: база по ИБ закрыта, сертификат выдали. Без «вау», но претензий к честности курса нет.', 't', '2026-04-09 09:22:41.509'),
('cmp67i07c05n1lk9c3os1fjrj', 'cmp677s8f00lclk1vpxz09aae', 'Искаков Владислав Олегович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-24, 2 курс', '3', 'Прошла курс целиком. Нормально для программы: тесты честные, по практике комментарии полезные. Без «вау», но знания по ИБ реально прибавились.', 't', '2026-04-14 21:10:48.505'),
('cmp67i07f05nblk9cr7aswqw3', 'cmp677s8q00lolk1vl0oj9i0w', 'Саввинов Василий Витальевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-24, 2 курс', '5', 'Сильная линейка модулей, всё связано с реальными ошибками пользователей. Прошёл до конца без «затыков». Сертификат — приятное подтверждение, что не зря вложился.', 't', '2026-04-12 15:29:01.436'),
('cmp67i07c05n3lk9ctwc2vbpv', 'cmp677s8i00lflk1va2s6b2ac', 'Николаев Мирам Федорович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-24, 2 курс', '3', 'Нормальный курс для общей грамотности по ИБ. Всё закрыл, документ выдали. Без восторга, но жаловаться не на что — ровно то, что обещали.', 't', '2026-04-13 01:30:28.683'),
('cmp67i07d05n5lk9czm4k6oar', 'cmp677s8l00lilk1v4w3179wo', 'Николаев Никон Аввакумович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-24, 2 курс', '3', 'Ровный курс, прошёл до конца. Тесты справедливые, практика полезная. Четвёрку не ставлю из‑за ощущения «чуть не дожали» финал.', 't', '2026-04-12 06:43:07.976'),
('cmp67i07d05n7lk9cbk4grc55', 'cmp677s8o00lllk1vifj0vw8r', 'Ничипоренко Андрей Артемович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-24, 2 курс', '5', 'Отлично: и фишинг, и устройства, и сети — без перегруза. Закрыл всё, сертификат приятный бонус. Одногруппникам уже скинул ссылку.', 't', '2026-04-08 13:55:22.565'),
('cmp67i07e05n9lk9c8wegdyi3', 'cmp5mtbof0023gnh8xs625cmb', 'Андросов Александр', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '5', 'Отлично структурировано: от простого к сложному, везде понятно, зачем этот шаг. Практика с ручной проверкой мотивировала не халтурить. После выдачи сертификата спокойно рассказываю одногруппникам, с чего начать ИБ.', 't', '2026-04-08 00:51:47.766'),
('cmp67i07f05ndlk9cl0beav9m', 'cmp677s8s00lrlk1v6dv8zsjh', 'Седых Ярослав Кириллович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-24, 2 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-04-12 05:11:54.01'),
('cmp67i07o05oblk9cir5is6x8', 'cmp5mtbpd0033gnh8is2gom4d', 'Нехоруков Сергей', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '3', 'Прошла полностью на заочке. Нормально, без сюрпризов: тесты, практика, документ. Хотелось бы чуть больше голосовых/видео пояснений, но это вкусовщина.', 't', '2026-04-12 23:11:24.255'),
('cmp67i07i05nplk9chi952b8f', 'cmp5mtboo0029gnh8kh88hc0n', 'Афонский Марк', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '4', 'Как программисту, зашло сочетание «теория + руки». Прошёл полностью. Сертификат пригодится. Не пять звёзд только из‑за пары опечаток в заданиях.', 't', '2026-04-12 05:00:56.845'),
('cmp67i07y05pflk9c9y8ldnd2', 'cmp5n9dk5004lgnmmz5371v6k', 'Алексеев Эрчим', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '4', 'Хороший баланс теории и проверок. Все модули закрыл, к сертификату претензий нет. Звезду снял за то, что мобильная вёрстка местами прыгает.', 't', '2026-04-11 18:15:26.385'),
('cmp67i05u05hhlk9cazxsglge', 'cmp66xijw00drlktgja9yj2c5', 'Иванов Гаврил Гаврильевич', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-9-22, 4 курс', '5', 'Заочно учиться непросто, но здесь всё разложено по полочкам: понятно, что делать каждый день. Курс завершил, сертификат забрал — горжусь.', 't', '2026-04-11 11:12:34.182'),
('cmp67i07h05njlk9cti73x67x', 'cmp677s8z00m0lk1v62bt85h1', 'Цивилев Павел Сергеевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-24, 2 курс', '5', 'Очно на парах часто не хватает времени на «глубину» — здесь как раз она есть. Все модули закрыл, сертификат показал куратору. Топ.', 't', '2026-04-13 22:03:06.585'),
('cmp67i07h05nllk9cwkq22yiz', 'cmp677s9100m3lk1vmqg2gnpw', 'Яковлева Рада Иннокентьевна', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-24, 2 курс', '5', 'Очень понравилось, что нельзя «прокликать» практику бездумно — проверка реально заставляет думать. Курс полностью прошёл, сертификатом доволен.', 't', '2026-04-10 13:48:59.925'),
('cmp67i07i05nnlk9cup5sychz', 'cmp5mtbol0026gnh8rucqw91f', 'Апросимов Василий', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '3', 'Нормально для обязательного блока: база по ИБ закрыта, сертификат выдали. Без «вау», но претензий к честности курса нет.', 't', '2026-04-10 19:45:52.555'),
('cmp67i07j05nrlk9cl38o6rrt', 'cmp5mtbor002cgnh8qj3jd88c', 'Баишев Николай', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '2', 'Курс закончил, но тяжеловато по нагрузке параллельно с парой. Иногда не хватало пошаговых подсказок в практике. Итог: полезно, но не идеально.', 't', '2026-04-09 13:40:32.375'),
('cmp67i07j05ntlk9c5t09mx92', 'cmp5mtbou002fgnh8f7zzcf2w', 'Батурин Антон', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '5', 'Заочно учиться непросто, но здесь всё разложено по полочкам: понятно, что делать каждый день. Курс завершил, сертификат забрал — горжусь.', 't', '2026-04-14 21:07:57.527'),
('cmp67i07k05nxlk9ci6i2i88w', 'cmp5mtbow002ignh8h1zq0ui6', 'Горбунов Никита', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '5', 'Отлично выстроено под заочников: короткие сессии, понятные задания. Прошёл до конца без выгорания. Сертификат — приятное завершение.', 't', '2026-04-12 15:16:11.379'),
('cmp67i07l05nzlk9c4g6vb88n', 'cmp5mtboz002lgnh8gmmfbl7h', 'Дорофеев Максим', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '5', 'Заочно учиться непросто, но здесь всё разложено по полочкам: понятно, что делать каждый день. Курс завершил, сертификат забрал — горжусь.', 't', '2026-04-15 04:36:13.323'),
('cmp67i07l05o1lk9cg6mpmsqg', 'cmp5mtbp1002ognh816fv0105', 'Иванов Иннокентий', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '4', 'Хорошо стыкуется с очным расписанием: можно догнать дома. Сертификат получил. Минус — иногда неочевидно, где сохранился черновик практики.', 't', '2026-04-16 21:09:53.873'),
('cmp67i07m05o3lk9cy64xbuiz', 'cmp5mtbp4002rgnh8nmi6edvo', 'Иванова Александрина', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '3', 'Прошла полностью на заочке. Нормально, без сюрпризов: тесты, практика, документ. Хотелось бы чуть больше голосовых/видео пояснений, но это вкусовщина.', 't', '2026-04-13 09:48:45.202');